mapper.select:
SELECT r.REQ_ID AS requestId, CONVERT(VARCHAR(10), r.TARGET_DATE, 23) AS workDate, CASE WHEN r.REQ_GROUP = 'OTHER' THEN 'OTHER' WHEN r.REQ_TYPE IN ('연장', '조출연장') THEN 'OVERTIME' WHEN r.REQ_TYPE = '휴일근무' THEN 'HOLIDAY' ELSE 'LEAVE' END AS requestCategory, CASE WHEN r.REQ_GROUP = 'OTHER' THEN o.CHANGE_SHIFT_CODE ELSE r.REQ_TYPE END AS requestWorkCode, r.TARGET_EMP_CODE AS empCode, te.EMP_NAME AS empName, r.TARGET_DEPT_CODE AS deptCode, td.DEPT_NAME AS deptName, r.REQUESTER_EMP_CODE AS requesterCode, re.EMP_NAME AS requesterName, r.REASON AS reason, r.REASON_DETAIL AS reasonDetail, LEFT(CONVERT(VARCHAR(8), g.START_TIME, 108), 5) AS startTime, ISNULL(g.START_TIME_TYPE, 'N0') AS startTimeType, LEFT(CONVERT(VARCHAR(8), g.END_TIME, 108), 5) AS endTime, ISNULL(g.END_TIME_TYPE, 'N0') AS endTimeType, g.WORK_MIN AS requestWorkMin, r.STATUS AS status, CONVERT(VARCHAR(19), r.CREATED_AT, 120) AS requestedAt, CONVERT(VARCHAR(19), r.UPDATED_AT, 120) AS updatedAt FROM HRTATTENDANCEREQUEST01 r LEFT JOIN HRTATTENDANCE_GENERAL01 g ON r.COMPANY = g.COMPANY AND r.REQ_ID = g.REQ_ID LEFT JOIN HRTATTENDANCE_OTHER01 o ON r.COMPANY = o.COMPANY AND r.REQ_ID = o.REQ_ID LEFT JOIN HRIMASTER01 te ON r.COMPANY = te.COMPANY AND r.TARGET_EMP_CODE = te.EMP_CODE LEFT JOIN HRIMASTER01 re ON r.COMPANY = re.COMPANY AND r.REQUESTER_EMP_CODE = re.EMP_CODE LEFT JOIN ORGDEPTMASTER01 td ON r.COMPANY = td.COMPANY AND r.TARGET_DEPT_CODE = td.DEPT_CODE WHERE r.COMPANY = #{company} AND r.TARGET_DATE BETWEEN CAST(#{fromDate} AS DATE) AND CAST(#{toDate} AS DATE)
AND (r.REQUESTER_EMP_CODE = #{loginEmpCode} OR r.TARGET_EMP_CODE = #{loginEmpCode})
AND r.TARGET_DEPT_CODE = #{deptCode}
AND r.TARGET_EMP_CODE = #{empCode}
AND r.STATUS = #{status}
AND r.REQ_GROUP = 'OTHER'
AND r.REQ_GROUP = 'GENERAL' AND r.REQ_TYPE IN ('연장', '조출연장')
AND r.REQ_GROUP = 'GENERAL' AND r.REQ_TYPE = '휴일근무'
AND r.REQ_GROUP = 'GENERAL' AND r.REQ_TYPE NOT IN ('연장', '조출연장', '휴일근무')
ORDER BY r.TARGET_DATE DESC, r.CREATED_AT DESC

SELECT COUNT(*)
FROM HRTATTENDANCEREQUEST01 r
LEFT JOIN HRTATTENDANCE_OTHER01 o
       ON r.COMPANY = o.COMPANY AND r.REQ_ID = o.REQ_ID
WHERE r.COMPANY = #{company}
  AND r.TARGET_EMP_CODE = #{empCode}
  AND r.TARGET_DATE = CAST(#{workDate} AS DATE)
  AND r.STATUS IN ('DRAFT', 'SUBMITTED', 'APPROVED')

      AND r.REQ_ID <> #{requestId}



          AND r.REQ_GROUP = 'OTHER'


          AND r.REQ_GROUP = 'GENERAL'
          AND r.REQ_TYPE = #{requestWorkCode}

mapper.update:
UPDATE HRTATTENDANCE_OTHER01
SET CHANGE_SHIFT_CODE = #{requestWorkCode},
    UPDATED_AT        = GETDATE()
WHERE REQ_ID  = #{requestId}
  AND COMPANY = #{company}

mapper.select:
SELECT DEPT_LEADER
FROM ORGDEPTMASTER01
WHERE COMPANY = #{company}
  AND DEPT_CODE = #{deptCode}

SELECT COUNT(*)
FROM HRTATTENDANCEREQUEST01
WHERE COMPANY         = #{company}
  AND TARGET_EMP_CODE = #{empCode}
  AND TARGET_DATE     = CAST(#{workDate} AS DATE)
  AND STATUS IN ('DRAFT', 'SUBMITTED', 'APPROVED')
  AND REQ_GROUP = 'GENERAL'

      AND REQ_ID <> #{requestId}



          AND REQ_TYPE = '조퇴'


          AND REQ_TYPE IN ('연장', '조출연장')

SELECT COUNT(*)
FROM HRTDAILYATTENDANCE01
WHERE COMPANY = #{company}
  AND EMP_CODE = #{empCode}
  AND YYYYMMDD = REPLACE(#{workDate}, '-', '')
  AND CHECK_IN IS NOT NULL

SELECT COUNT(*) FROM HRTATTENDANCEREQUEST01 r JOIN HRTATTENDANCE_GENERAL01 g ON r.COMPANY = g.COMPANY AND r.REQ_ID = g.REQ_ID WHERE r.COMPANY = #{company} AND r.TARGET_EMP_CODE = #{empCode} AND r.TARGET_DATE = CAST(#{workDate} AS DATE) AND r.STATUS IN ('DRAFT', 'SUBMITTED', 'APPROVED') AND r.REQ_GROUP = 'GENERAL' AND r.REQ_TYPE <> #{requestWorkCode} AND ( (#{requestWorkCode} IN ('연장', '조출연장', '휴일근무') AND r.REQ_TYPE IN ('연장', '조출연장', '휴일근무')) OR (#{requestWorkCode} IN ('조퇴', '외근', '외출', '전반차', '후반차', '오전반차', '오후반차') AND r.REQ_TYPE IN ('조퇴', '외근', '외출', '전반차', '후반차', '오전반차', '오후반차')) ) AND g.START_TIME IS NOT NULL AND g.END_TIME IS NOT NULL
AND r.REQ_ID <> #{requestId}
AND ( (CASE WHEN ISNULL(g.START_TIME_TYPE, 'N0') = 'N1' THEN 1440 ELSE 0 END + DATEDIFF(MINUTE, CAST('00:00' AS TIME), g.START_TIME)) < (CASE WHEN #{endTimeType} = 'N1' THEN 1440 ELSE 0 END + DATEDIFF(MINUTE, CAST('00:00' AS TIME), CAST(#{endTime} AS TIME))) ) AND ( (CASE WHEN #{startTimeType} = 'N1' THEN 1440 ELSE 0 END + DATEDIFF(MINUTE, CAST('00:00' AS TIME), CAST(#{startTime} AS TIME))) < (CASE WHEN ISNULL(g.END_TIME_TYPE, 'N0') = 'N1' THEN 1440 ELSE 0 END + DATEDIFF(MINUTE, CAST('00:00' AS TIME), g.END_TIME)) )
